DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "PGchoicemacros.pl",
  "contextForm.pl",
  "contextFraction.pl",
  "parserPopUp.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
($x,$y) = (-8..-1,1..8)[NchooseK(16,2)];
@b = (-9..$y-1,$y+1..9)[NchooseK(18,2)];
Context("Fraction");
Context()->noreduce('(-x)+y', '(-x)-y');
@m = map{Fraction(($y - $_)/$x)} (@b);
@n = map{($_->value)[0]} (@m);
@d = map{($_->value)[1]} (@m);
@f = map{Formula("$m[$_] x + $b[$_]")->reduce} (0,1);
Context("Point");
$solution = Point($x,$y);
do {
  $x1 = random(0, 9, $d[0]);
  $y1 = $f[0]->eval(x => $x1);
} until ($x1 != $x);
$proposed_solution = Point($x1,$y1);
$dropdown = DropDown(["Yes, it is a solution.", "No, it is not a solution."], 1, showInStatic => 0);

############################################################
# Body
############################################################

BEGIN_PGML
Check if the given point is a solution to the given system of two linear equations.

Is [`[$proposed_solution]`] a solution?

[`\newcommand{\amp}{&}
                  \left\{
                    \begin{alignedat}{3}
                      y\amp= [$f[0]]\\
                      y\amp= [$f[1]]
                    \end{alignedat}
                  \right.
                `]

[_]{$dropdown}{5}

END_PGML

############################################################
# End Problem
############################################################

ENDDOCUMENT();
